mapper.insert:
INSERT INTO archive_board_info (
      title
    , content
    , writer
    , view_cnt
    , notice_yn
    , delete_yn
    , created_date
    , modified_date
) VALUES (
      #{title}
    , #{content}
    , #{writer}
    , 0
    , #{noticeYn}
    , 0
    , NOW()
    , NULL
)

mapper.update:
UPDATE archive_board_info
SET
      modified_date = NOW()
    , title = #{title}
    , content = #{content}
    , writer = #{writer}
    , notice_yn = #{noticeYn}
WHERE board_id = #{boardId}

UPDATE archive_board_info
SET delete_yn = 1
WHERE board_id = #{value}

mapper.select:
SELECT
FROM archive_board_info WHERE delete_yn = 0
ORDER BY board_id DESC LIMIT #{pagination.limitStart}, #{recordSize}

mapper.update:
UPDATE archive_board_info
SET view_cnt = view_cnt + 1
WHERE board_id = #{value}
